mapper.sql:
selected_roots AS ( SELECT DEPARTMENT_ID AS root_id, DEPARTMENT_NAME AS root_name FROM DEPARTMENT WHERE USE_YN = 'Y' AND DEPARTMENT_ID IN
#{departmentId}
), selected_tree AS ( SELECT CONNECT_BY_ROOT d.DEPARTMENT_ID AS root_id, d.DEPARTMENT_ID AS department_id FROM DEPARTMENT d WHERE d.USE_YN = 'Y' START WITH d.DEPARTMENT_ID IN
#{departmentId}
CONNECT BY PRIOR d.DEPARTMENT_ID = d.PARENT_DEPARTMENT_ID )
